const body = items[0].json.body || items[0].json || {};
const bootMode = body.boot_mode || "normal";
const bootedAt = new Date().toISOString();

const systemManifest = {
  system_id: "AI5R",
  kernel: "OSA",
  architecture: "Asset-Oriented Operating Platform",
  version: "1.0.0"
};

const registry = {
  registry_version: "1.0.0",
  assets: [
    { asset_id: "OSA.KERNEL.GATEWAY.001", legacy_alias: ["OSA-KERNEL-001"], status: "active", asset_type: "kernel" },
    { asset_id: "OSA.KERNEL.CREDENTIAL_VAULT.001", legacy_alias: ["OSA-KERNEL-002"], status: "active", asset_type: "kernel" },
    { asset_id: "OSA.KERNEL.LOGGER.001", legacy_alias: ["OSA-KERNEL-003"], status: "active", asset_type: "kernel" },
    { asset_id: "OSA.KERNEL.REGISTRY.001", legacy_alias: ["OSA-KERNEL-004"], status: "active", asset_type: "kernel" },
    { asset_id: "OSA.KERNEL.HEALTH_MONITOR.001", legacy_alias: ["OSA-KERNEL-005"], status: "active", asset_type: "kernel" },
    { asset_id: "AI5R.PLATFORM.MEMORY.001", legacy_alias: ["AI5R-MEMORY"], status: "active", asset_type: "platform" },
    { asset_id: "AI5R.PLATFORM.GIT.001", legacy_alias: ["AI5R-GIT"], status: "active", asset_type: "platform" },
    { asset_id: "AI5R.PLATFORM.ARTIFACT.001", legacy_alias: ["AI5R-ARTIFACT"], status: "active", asset_type: "platform" }
  ]
};

const dependencyGraph = {
  "AI5R.PLATFORM.MEMORY.001": ["OSA.KERNEL.REGISTRY.001", "OSA.KERNEL.LOGGER.001"],
  "AI5R.PLATFORM.GIT.001": ["OSA.KERNEL.GATEWAY.001", "OSA.KERNEL.LOGGER.001"],
  "AI5R.PLATFORM.ARTIFACT.001": ["AI5R.PLATFORM.MEMORY.001", "AI5R.PLATFORM.GIT.001"]
};

const assets = registry.assets;
const assetMap = Object.fromEntries(assets.map(a => [a.asset_id, a]));
const visited = new Set();
const loading = new Set();
const loadOrder = [];
const errors = [];

function visit(id) {
  if (visited.has(id)) return;
  if (loading.has(id)) {
    errors.push(`Circular dependency detected: ${id}`);
    return;
  }
  loading.add(id);
  for (const dep of dependencyGraph[id] || []) {
    if (!assetMap[dep]) errors.push(`Missing dependency ${dep} for ${id}`);
    else visit(dep);
  }
  loading.delete(id);
  visited.add(id);
  if (assetMap[id]) loadOrder.push(id);
}

for (const asset of assets) visit(asset.asset_id);

const failed = errors.length;
const runtimeState = {
  status: failed ? "DEGRADED" : "READY",
  product: "OSA",
  service: "OSA-RUNTIME-CORE-001",
  version: "1.0.0",
  boot_mode: bootMode,
  booted_at: bootedAt,
  system_manifest: systemManifest,
  modules_loaded: loadOrder.length,
  failed_modules: failed,
  load_order: loadOrder,
  loaded_modules: loadOrder.map(id => ({ asset_id: id, status: "loaded", loaded_at: bootedAt })),
  running_missions: [],
  health: failed ? "degraded" : "healthy",
  errors
};

return [{ json: { runtimeState } }];

const state = items[0].json.runtimeState || items[0].json;
return [{
  json: {
    success: state.failed_modules === 0,
    product: "OSA",
    service: "OSA-RUNTIME-CORE-001",
    version: state.version || "1.0.0",
    status: state.status || "READY",
    boot_time: state.booted_at,
    modules_loaded: state.modules_loaded || 0,
    failed_modules: state.failed_modules || 0,
    health: state.health || "healthy",
    load_order: state.load_order || [],
    errors: state.errors || []
  }
}];
